import anthropic
import json
import re

client = anthropic.Anthropic()

EXTRACTION_SYSTEM = """
You extract structured data from text.
Return only valid JSON matching the required schema. No explanation.
"""

def extract(text: str, schema_description: str, previous_issues: str | None = None) -> str:
    user_msg = f"Schema:\n{schema_description}\n\nText to extract from:\n{text}"
    if previous_issues:
        user_msg += f"\n\nYour previous output had these issues:\n{previous_issues}\n\nFix and retry."
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=256,
        system=EXTRACTION_SYSTEM,
        messages=[{"role": "user", "content": user_msg}],
    )
    return resp.content[0].text.strip()

def validate_person(raw: str) -> dict:
    """Rule-based validator: no LLM call."""
    try:
        obj = json.loads(raw)
    except json.JSONDecodeError as e:
        return {"passes": False, "issues": [f"JSON parse error: {e}"]}

    issues = []
    required = {"name": str, "age": int, "email": str}
    for field, expected_type in required.items():
        if field not in obj:
            issues.append(f"Missing field: {field}")
        elif not isinstance(obj[field], expected_type):
            issues.append(f"{field} must be {expected_type.__name__}, got {type(obj[field]).__name__}")

    if "age" in obj and isinstance(obj["age"], int):
        if not (0 <= obj["age"] <= 150):
            issues.append(f"age {obj['age']} is out of range [0, 150]")
    if "email" in obj and isinstance(obj["email"], str):
        if not re.match(r"^[^@]+@[^@]+\.[^@]+$", obj["email"]):
            issues.append(f"email '{obj['email']}' does not look valid")

    return {"passes": len(issues) == 0, "issues": issues}

def extract_with_validation(text: str, max_rounds: int = 3) -> dict:
    schema_desc = (
        "person object with fields: name (string), age (integer 0-150), "
        "email (string, must be a valid email address)"
    )
    issues_str = None
    for round_num in range(1, max_rounds + 1):
        raw = extract(text, schema_desc, issues_str)
        result = validate_person(raw)
        if result["passes"]:
            return {"status": "passed", "rounds": round_num, "output": json.loads(raw)}
        issues_str = "\n".join(result["issues"])
    return {"status": "max_rounds", "rounds": max_rounds, "last_raw": raw, "issues": issues_str}

text = "Dr. Jane Smith, born in 1987 (age 38), can be reached at jane.smith@example.com."
result = extract_with_validation(text)
print(result)

import anthropic
import json

client = anthropic.Anthropic()

VERIFIER_SYSTEM = """
You are a fact-checker. You are given a source passage and a claim.
Determine whether the source supports, contradicts, or does not address the claim.

Return JSON:
{
  "verdict": "supported" | "contradicted" | "not_addressed",
  "explanation": "One sentence citing the specific part of the source that led to this verdict.",
  "confidence": "high" | "medium" | "low"
}
Be strict: a claim is "supported" only if the source explicitly states it.
A claim that the source implies but does not state is "not_addressed".
"""

def verify_claim_against_source(claim: str, source: str) -> dict:
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=200,
        system=VERIFIER_SYSTEM,
        messages=[{"role": "user", "content": f"Source:\n{source}\n\nClaim:\n{claim}"}],
    )
    try:
        return json.loads(resp.content[0].text)
    except json.JSONDecodeError:
        return {"verdict": "not_addressed", "explanation": "Parse error", "confidence": "low"}

def verify_answer_against_sources(answer: str, sources: list[str]) -> dict:
    """
    Split the answer into sentences and verify each against all sources.
    Returns a verdict for each sentence.
    """
    import re
    sentences = [s.strip() for s in re.split(r'(?<=[.!?])\s+', answer) if s.strip()]
    verdicts = []
    for sentence in sentences:
        best_verdict = None
        for i, source in enumerate(sources):
            v = verify_claim_against_source(sentence, source)
            if v["verdict"] == "contradicted":
                best_verdict = {**v, "source_index": i, "sentence": sentence}
                break  # contradicted is definitive — stop checking
            if v["verdict"] == "supported" and v["confidence"] == "high":
                best_verdict = {**v, "source_index": i, "sentence": sentence}
        if best_verdict is None:
            best_verdict = {"verdict": "not_addressed", "sentence": sentence,
                            "explanation": "No source explicitly supports this claim.",
                            "confidence": "low", "source_index": -1}
        verdicts.append(best_verdict)
    issues = [v for v in verdicts if v["verdict"] != "supported"]
    return {"passes": len(issues) == 0, "verdicts": verdicts, "issues": issues}

source1 = (
    "The Eiffel Tower is located in Paris, France. It was designed by Gustave Eiffel "
    "and constructed between 1887 and 1889 as the entrance arch for the 1889 World's Fair."
)
answer = "The Eiffel Tower is in Paris. It was designed by Gustave Eiffel in 1885."
result = verify_answer_against_sources(answer, [source1])
for v in result["verdicts"]:
    print(f"{v['verdict'].upper()}: {v['sentence']}")
    print(f"  -> {v['explanation']}")
# SUPPORTED: The Eiffel Tower is in Paris.
# CONTRADICTED: It was designed by Gustave Eiffel in 1885.
#   -> Source states construction was 1887-1889, not designed in 1885.

import anthropic
import json

client = anthropic.Anthropic()

RESEARCH_SYSTEM = """
You are a research assistant. Answer questions step by step.

When you have an answer, call verify_claim for each key fact in your answer.
Only call task_complete after every claim has been verified.
If verify_claim returns contradicted=true for any claim, revise your answer and re-verify.
If you cannot verify a claim, include uncertainty language in your final answer.
"""

# Stub knowledge base: maps keywords to source passages
KNOWLEDGE_BASE = {
    "mount everest height": "Mount Everest's height is 8,848.86 m (29,031.7 ft) as measured in 2020.",
    "mount everest location": "Mount Everest is located in the Mahalangur Himal sub-range of the Himalayas on the Nepal-Tibet border.",
    "everest first ascent": "Mount Everest was first climbed on 29 May 1953 by Edmund Hillary and Tenzing Norgay.",
}

def search(query: str) -> str:
    q = query.lower()
    for key, passage in KNOWLEDGE_BASE.items():
        if any(word in q for word in key.split()):
            return json.dumps({"found": True, "passage": passage})
    return json.dumps({"found": False, "message": "No relevant source found."})

VERIFIER_SYSTEM = """
You are a strict fact-checker.
Given a source passage and a claim, return JSON:
{
  "supported": true or false,
  "contradicted": true or false,
  "explanation": "..."
}
Only mark supported=true if the source explicitly states the claim.
"""

def verify_claim(claim: str, source: str) -> str:
    if not source or source == "none":
        return json.dumps({"supported": False, "contradicted": False,
                           "explanation": "No source provided — cannot verify."})
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=150,
        system=VERIFIER_SYSTEM,
        messages=[{"role": "user", "content": f"Source: {source}\n\nClaim: {claim}"}],
    )
    try:
        return resp.content[0].text.strip()
    except Exception:
        return json.dumps({"supported": False, "contradicted": False,
                           "explanation": "Verification error."})

TOOLS = [
    {"name": "search",
     "description": "Search the knowledge base for a passage relevant to a query.",
     "input_schema": {"type": "object",
                      "properties": {"query": {"type": "string"}},
                      "required": ["query"]}},
    {"name": "verify_claim",
     "description": "Verify that a claim is supported by a source passage.",
     "input_schema": {"type": "object",
                      "properties": {
                          "claim": {"type": "string", "description": "The specific claim to verify"},
                          "source": {"type": "string", "description": "The passage to verify against"},
                      },
                      "required": ["claim", "source"]}},
    {"name": "task_complete",
     "description": "Submit the final verified answer.",
     "input_schema": {"type": "object",
                      "properties": {"answer": {"type": "string"}},
                      "required": ["answer"]}},
]
DISPATCH = {"search": search, "verify_claim": verify_claim}

def run_verified_research_agent(question: str, max_iterations: int = 12) -> dict:
    messages = [{"role": "user", "content": question}]
    for _ in range(max_iterations):
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            system=RESEARCH_SYSTEM,
            tools=TOOLS,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": resp.content})
        tool_calls = [b for b in resp.content if b.type == "tool_use"]
        for block in tool_calls:
            if block.name == "task_complete":
                return {"status": "complete", "answer": block.input["answer"]}
        if not tool_calls:
            return {"status": "stuck"}
        results = []
        for block in tool_calls:
            fn = DISPATCH.get(block.name)
            result = fn(**block.input) if fn else json.dumps({"error": "Unknown tool"})
            results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})
        messages.append({"role": "user", "content": results})
    return {"status": "max_iterations"}

outcome = run_verified_research_agent("How tall is Mount Everest, and who first climbed it?")
print(outcome)
